import{_ as t,o as l,c as r,a2 as i}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"F04: 業外收支純度與收益質量 - 財務審計專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3105_穩懋/20260503/F04_業外收支純度與收益質量.md","filePath":"審計報告庫/財務審計/3105_穩懋/20260503/F04_業外收支純度與收益質量.md"}'),o={name:"審計報告庫/財務審計/3105_穩懋/20260503/F04_業外收支純度與收益質量.md"};function e(n,a,s,$,h,d){return l(),r("div",null,[...a[0]||(a[0]=[i('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f04-業外收支純度與收益質量-財務審計專家-審計報告" tabindex="-1">F04: 業外收支純度與收益質量 - 財務審計專家 審計報告 <a class="header-anchor" href="#f04-業外收支純度與收益質量-財務審計專家-審計報告" aria-label="Permalink to &quot;F04: 業外收支純度與收益質量 - 財務審計專家 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>業外收支 (Non-Operating) 規模與組成細項為何？是長期投資收益還是匯兌/利息等雜項損益？是否存在獲利虛胖風險？識別非核心業務損益對 EPS 的貢獻佔比。</p></blockquote><h2 id="🎯-專家直斷-53-字" tabindex="-1">🎯 專家直斷（53 字） <a class="header-anchor" href="#🎯-專家直斷-53-字" aria-label="Permalink to &quot;🎯 專家直斷（53 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：業外佔稅前 48.5% 遠超 20% 警戒，含 NT$1.95B 處分利得與 NT$1.64B 減損對沖。核心 EPS 約 NT$2.5，帳面 NT$4.00 依賴一次性項目。</li><li><strong>風險評級</strong>：高</li><li><strong>數據時效</strong>：根據截至 2025 年最新公開數據</li></ul><h2 id="📊-診斷評級-143-字" tabindex="-1">📊 診斷評級（143 字） <a class="header-anchor" href="#📊-診斷評級-143-字" aria-label="Permalink to &quot;📊 診斷評級（143 字）&quot;">​</a></h2><ul><li><strong>重點數據</strong>：業外佔稅前 48.5%（$672M/$1,387M），主因處分利得 $1.95B 與減損 $1.64B 對沖。常態化稅前 $1.076B、EPS $3.12。</li><li><strong>診斷見解</strong>：業外佔比遠超 20% 警戒，獲利高度依賴一次性項目，扣除後 EPS 低估 22%，獲利純度不足。</li></ul><h2 id="🔍-答詢詳解-429-字" tabindex="-1">🔍 答詢詳解（429 字） <a class="header-anchor" href="#🔍-答詢詳解-429-字" aria-label="Permalink to &quot;🔍 答詢詳解（429 字）&quot;">​</a></h2><h3 id="收益結構透視-業外三大核心來源拆解" tabindex="-1">收益結構透視：業外三大核心來源拆解 <a class="header-anchor" href="#收益結構透視-業外三大核心來源拆解" aria-label="Permalink to &quot;收益結構透視：業外三大核心來源拆解&quot;">​</a></h3><ul><li><strong>核心重點</strong>：其他利益及損失 $688M（102.3%）：①處分 PP&amp;E $1.95B；②減損 $1.64B；③匯兌 $335M。①+②近對沖，淨約 $311M。股利 $192M 較去年 $38M 暴增。</li><li><strong>深度見解</strong>：2024 年業外淨損 $429M，2025 年翻正來自資產出售，非業外已建立常態。</li></ul><h3 id="雜訊敏感度-匯率與利率雙重暴露" tabindex="-1">雜訊敏感度：匯率與利率雙重暴露 <a class="header-anchor" href="#雜訊敏感度-匯率與利率雙重暴露" aria-label="Permalink to &quot;雜訊敏感度：匯率與利率雙重暴露&quot;">​</a></h3><ul><li><strong>核心重點</strong>：淨利息 $521M 佔營益 72.9%。匯兌 $335M 具高迴轉風險，台幣升值 3% 可轉為 $500-800M 損失。</li><li><strong>深度見解</strong>：70-80% 營收以美元計，台幣每升 1 元影響 EPS $0.5-0.8。</li></ul><h3 id="可持續性評價-扣非後的真實獲利基座" tabindex="-1">可持續性評價：扣非後的真實獲利基座 <a class="header-anchor" href="#可持續性評價-扣非後的真實獲利基座" aria-label="Permalink to &quot;可持續性評價：扣非後的真實獲利基座&quot;">​</a></h3><ul><li><strong>核心重點</strong>：常態化稅前 $845M（營益 $715M + 利息收入 $154M + 股利 $50M + 權益法 $266M + 匯兌 $335M - 利息 $675M），較帳面 $1,387M 落差 39%，常態化 EPS $2.3-3.1。</li><li><strong>深度見解</strong>：常態化 PER 約 130-173 倍，獲利可持續性堪憂。</li></ul><h2 id="💡-專家評析-412-字-≥2-個利空關鍵字" tabindex="-1">💡 專家評析（412 字，≥2 個利空關鍵字） <a class="header-anchor" href="#💡-專家評析-412-字-≥2-個利空關鍵字" aria-label="Permalink to &quot;💡 專家評析（412 字，≥2 個利空關鍵字）&quot;">​</a></h2><ol><li><p><strong>資產處分利得掩蓋本業獲利停滯的風險</strong>：2025 年營業利益 NT$715M 較 2024 年 NT$762M 衰退 6.2%，本業獲利並未隨營收改善而成長。非營業項目包含 NT$1.95B 的處分資產利益（推測為閒置廠房或土地活化），幾乎完全對應 NT$1.64B 的減損損失。此「同額沖銷」模式暗示管理層可能在進行資產組合重整，但一次性利益無法覆蓋本業獲利的下滑壓力。若扣除一次性項目，EPS 將從 NT$4.00 降至 NT$2.5-3.0 區間。</p></li><li><p><strong>高利息成本壓縮獲利空間</strong>：2025 年利息支出 NT$675M 為利息收入 NT$154M 的 4.4 倍，淨利息成本佔營益率達 72.9%。雖較 2024 年（利息支出 NT$795M）有所改善，但財務槓桿仍偏高。2025 年償還長期借款 NT$7.99B 有助去槓桿，但若利率環境維持高檔，利息支出仍將持續侵蝕獲利。匯兌利益 NT$335M 亦存在高迴轉風險——一旦台幣升值趨勢反轉，將直接壓縮稅前盈餘。</p></li><li><p><strong>權益法與股利收入結構性偏低</strong>：權益法收益 NT$266M 雖較 2024 年翻倍，但僅佔稅前 19.2%，且主要來自關聯企業（穩盈等），尚不足以成為穩定業外支柱。股利收入從 NT$38M 暴增至 NT$192M，若為一次性特別股利，2026 年將出現明顯缺口。</p></li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：數據採集器.py (finance 3105)</li><li>原始數據：FinMind TaiwanStockFinancialStatements</li><li>年報 PDF：2025_Q4_3105_合併.pdf（合併綜合損益表 p.9；業外收支附註 p.57-60）</li><li>查詢參數：stock_id=3105, start=2023-01-01, end=2025-12-31</li><li>關鍵核對碼：2025 NonOp=NT$672,193K, 處分資產利得NT$1,953,270K, 減損損失NT$1,641,913K, 稅前淨利NT$1,386,895K</li></ul>',19)])])}const u=t(o,[["render",e]]);export{c as __pageData,u as default};
